fn solve(nums: Vec<i64>) -> bool {
    let n = nums.len();
    if n < 3 {
        return false;
    }

    let mut p = 1;
    let mut q = n - 2;

    // Find p such that nums[0...p] is strictly increasing
    while p < n - 1 && nums[p] > nums[p - 1] {
        p += 1;
    }

    // Find q such that nums[q...n-1] is strictly increasing
    while q > 0 && nums[q] > nums[q - 1] {
        q -= 1;
    }

    // Check if p and q are valid indices
    if p >= n || q < 0 {
        return false;
    }

    // Check if nums[p...q] is strictly decreasing
    for i in p..q {
        if nums[i] <= nums[i + 1] {
            return false;
        }
    }

    true
}
